import React, { useEffect, useState } from "react";
import API from "../../api/api";

// ✅ value = DB-ல store ஆவது, label = display பண்றது
const categories = [
  { value: "All",                 label: "All" },
  { value: "web-development",     label: "Web Development" },
  { value: "mobile-development",  label: "Mobile Development" },
  { value: "ui-ux-design",        label: "UI/UX Design" },
  { value: "graphic-design",      label: "Graphic Design" },
  { value: "backend-development", label: "Backend Development" },
  { value: "data-science",        label: "Data Science & ML" },
  { value: "devops",              label: "DevOps & Cloud" },
  { value: "content-writing",     label: "Content Writing" },
  { value: "digital-marketing",   label: "Digital Marketing" },
  { value: "video-editing",       label: "Video Editing" },
  { value: "seo",                 label: "SEO" },
  { value: "cybersecurity",       label: "Cybersecurity" },
  { value: "other",               label: "Other" },
];

const FindProjects = () => {
  const [projects, setProjects] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [loading, setLoading] = useState(true);

  // ================= FETCH PROJECTS =================
  useEffect(() => {
    const fetchProjects = async () => {
      try {
        console.log("Fetching projects...");

        const res = await API.get("/projects");

        console.log("Projects Response:", res.data);

        setProjects(res.data || []);
      } catch (err) {
        console.error("Error fetching projects:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchProjects();
  }, []);

  // ================= FILTER =================
  const filteredProjects = projects.filter((project) => {
    const matchesSearch = project.title
      ?.toLowerCase()
      .includes(search.toLowerCase());

    // ✅ DB value comparison (web-development not "Web Development")
    const matchesCategory =
      selectedCategory === "All" ||
      project.category === selectedCategory;

    return matchesSearch && matchesCategory;
  });

  // ================= SEND PROPOSAL =================
  const sendProposal = async (projectId) => {
    const bid = prompt("Enter Your Bid Amount");
    const message = prompt("Enter Proposal Message");

    if (!bid || !message) return;

    try {
      await API.post("/proposals", {
        project_id: projectId,
        bid,
        message,
      });

      alert("Proposal Sent Successfully");
    } catch (error) {
      console.error(error);
      alert("Error sending proposal");
    }
  };

  return (
    <div className="bg-gray-50 min-h-screen p-10">
      <div className="max-w-6xl mx-auto">

        {/* TITLE */}
        <h1 className="text-3xl font-bold mb-6 text-gray-800">
          Find Projects
        </h1>

        {/* SEARCH + FILTER */}
        <div className="flex flex-col lg:flex-row gap-4 lg:items-center mb-8">

          {/* Search */}
          <input
            type="text"
            placeholder="Search projects..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="flex-1 px-4 py-3 border border-gray-300 rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-teal-500"
          />

          {/* Categories */}
          <div className="flex flex-wrap gap-3">
            {categories.map((cat) => (
              <button
                key={cat.value}
                onClick={() => setSelectedCategory(cat.value)}
                className={`px-4 py-2 rounded-full text-sm font-medium transition
                  ${
                    selectedCategory === cat.value
                      ? "bg-teal-600 text-white"
                      : "bg-gray-200 text-gray-700 hover:bg-gray-300"
                  }`}
              >
                {cat.label}
              </button>
            ))}
          </div>
        </div>

        {/* LOADING */}
        {loading && (
          <p className="text-gray-500">Loading projects...</p>
        )}

        {/* EMPTY STATE */}
        {!loading && filteredProjects.length === 0 && (
          <p className="text-gray-500">
            No projects found.
          </p>
        )}

        {/* PROJECT CARDS */}
        <div className="space-y-6">
          {filteredProjects.map((project) => (
            <div
              key={project.id}
              className="bg-white border border-gray-200 rounded-xl p-6 shadow-sm hover:shadow-md transition"
            >
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="text-xl font-semibold text-gray-800">
                    {project.title}
                  </h3>

                  <p className="text-gray-600 mt-2">
                    {project.description}
                  </p>
                </div>

                <span className="text-green-600 bg-green-100 px-3 py-1 rounded-full text-sm font-medium">
                  Open
                </span>
              </div>

              {project.skills && (
                <div className="flex flex-wrap gap-2 mt-4">
                  {project.skills.split(",").map((skill, index) => (
                    <span
                      key={index}
                      className="bg-gray-100 text-gray-700 px-3 py-1 rounded-full text-sm"
                    >
                      {skill.trim()}
                    </span>
                  ))}
                </div>
              )}

              <div className="border-t mt-6 pt-4 flex justify-between items-center">

                <div className="flex gap-6 text-gray-600 text-sm">
                  <span>₹ {project.budget}</span>
                  {project.deadline && <span>{project.deadline}</span>}
                  {project.company && <span>{project.company}</span>}
                </div>

                <div className="flex items-center gap-6">
                  <span className="text-teal-600 font-medium text-sm">
                    {project.proposalsCount || 0} proposals
                  </span>

                  <button
                    onClick={() => sendProposal(project.id)}
                    className="bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition"
                  >
                    Apply
                  </button>
                </div>

              </div>
            </div>
          ))}
        </div>

      </div>
    </div>
  );
};

export default FindProjects;
